  1→import express, { json } from "express";
  2→import cors from "cors";
  3→import fetch from "node-fetch";
  4→import dotenv from "dotenv";
  5→import Airtable from "airtable";
  6→
  7→const app = express();
  8→const port = process.env.PORT || 3000;
  9→
 10→dotenv.config({ path: ".env.backend" });
 11→const AIRTABLE_KEY = process.env.AIRTABLE_KEY;
 12→const AIRTABLE_ID = process.env.AIRTABLE_ID;
 13→const CAPTCHA_SECRET = process.env.CAPTCHA_SECRET;
 14→
 15→const edgyBase_backend = new Airtable({ apiKey: AIRTABLE_KEY }).base(
 16→  AIRTABLE_ID
 17→);
 18→
 19→app.use(
 20→  cors({
 21→    origin: "*",
 22→    methods: ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"],
 23→    allowedHeaders: ["Content-Type", "Authorization"],
 24→  })
 25→);
 26→app.use(json());
 27→
 28→app.get("/", (req, res) => {
 29→  res.send("Server Deployed 🥳");
 30→});
 31→
 32→app.get("/airtable", async (req, res) => {
 33→  const airtableUrl = `https://api.airtable.com/v0/${AIRTABLE_ID}/users`;
 34→
 35→  try {
 36→    const response = await fetch(airtableUrl, {
 37→      method: "GET",
 38→      headers: {
 39→        Authorization: `Bearer ${AIRTABLE_KEY}`,
 40→        "Content-Type": "application/json",
 41→      },
 42→    });
 43→    if (!response.ok) {
 44→      const errorData = await response.text();
 45→      throw new Error(
 46→        `HTTP error! Status: ${response.status}. Response: ${errorData}`
 47→      );
 48→    }
 49→
 50→    const data = await response.json();
 51→    return res.json(data);
 52→  } catch (error) {
 53→    console.error("Error:", error.message);
 54→    return res
 55→      .status(500)
 56→      .json({ error: "An error occurred while fetching data from Airtable." });
 57→  }
 58→});
 59→app.post("/airtable", async (req, res) => {
 60→  const { userId, formValue } = req.body;
 61→  const key = Object.keys(formValue)[0];
 62→  const value = Object.values(formValue)[0];
 63→  const form = { [key]: value };
 64→  try {
 65→    await edgyBase_backend("users").update([
 66→      {
 67→        id: userId,
 68→        fields: form,
 69→      },
 70→    ]);
 71→    res.status(200).json({ success: true });
 72→  } catch (error) {
 73→    res.status(500).json({ success: false, reason: error.message });
 74→  }
 75→});
 76→
 77→app.post("/verify-recaptcha", async (req, res) => {
 78→  const { token } = req.body;
 79→  const uri = `https://www.google.com/recaptcha/api/siteverify?secret=${CAPTCHA_SECRET}&response=${token}`;
 80→
 81→  fetch(uri, {
 82→    method: "post",
 83→  })
 84→    .then((response) => response.json())
 85→    .then((google_response) => {
 86→      if (google_response.success === true) {
 87→        return res.send({ response: "Successful" });
 88→      } else {
 89→        return res.send({ response: "Failed" });
 90→      }
 91→    })
 92→    .catch((error) => {
 93→      return res.json({ error });
 94→    });
 95→});
 96→
 97→app.listen(port, () =>
 98→  console.log(`Server is running on http://localhost:${port}`)
 99→);
100→

